CREATE TABLE IF NOT EXISTS chat_user (
    id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键',
    account_name VARCHAR(64) NOT NULL COMMENT '用户自定义账号名，唯一',
    password_hash VARCHAR(255) NOT NULL COMMENT 'BCrypt 密码哈希，不保存明文密码',
    points INT NOT NULL DEFAULT 0 COMMENT '当前积分余额，2147483647 约定为无限积分',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    CONSTRAINT uk_chat_user_account_name UNIQUE (account_name)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户表';

INSERT INTO chat_user (account_name, password_hash, points)
SELECT 'admin', '$2a$10$34/SHpT14lJYcIF72DCtW.hp4BIZAo8RU2IWu9/n82AGKlSzb0LaS', 2147483647
WHERE NOT EXISTS (
    SELECT 1 FROM chat_user WHERE account_name = 'admin'
);

CREATE TABLE IF NOT EXISTS chat_user_session (
    id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '会话主键',
    user_id BIGINT NOT NULL COMMENT '所属用户 ID',
    token_hash VARCHAR(64) NOT NULL COMMENT 'Bearer Token 的 SHA-256 哈希值',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '会话创建时间',
    last_used_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '最近使用时间',
    CONSTRAINT uk_chat_user_session_token_hash UNIQUE (token_hash),
    INDEX idx_chat_user_session_user_id (user_id),
    CONSTRAINT fk_chat_user_session_user FOREIGN KEY (user_id) REFERENCES chat_user(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='登录会话表';

CREATE TABLE IF NOT EXISTS chat_user_state (
    user_id BIGINT PRIMARY KEY COMMENT '用户 ID，同时作为主键，保证每个用户只保存一份状态',
    state_json LONGTEXT NOT NULL COMMENT '完整会话树 JSON',
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '最近更新时间',
    CONSTRAINT fk_chat_user_state_user FOREIGN KEY (user_id) REFERENCES chat_user(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户聊天状态表';

CREATE TABLE IF NOT EXISTS chat_user_redeem_code_usage (
    id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键',
    user_id BIGINT NOT NULL COMMENT '所属用户 ID',
    redeem_code VARCHAR(32) NOT NULL COMMENT '已兑换的兑换码',
    points_granted INT NOT NULL COMMENT '本次兑换实际发放的积分值，2147483647 约定为无限积分',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '兑换时间',
    INDEX idx_chat_user_redeem_user_id (user_id),
    CONSTRAINT uk_chat_user_redeem_user_code UNIQUE (user_id, redeem_code),
    CONSTRAINT fk_chat_user_redeem_user FOREIGN KEY (user_id) REFERENCES chat_user(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户兑换码使用记录表';

CREATE TABLE IF NOT EXISTS chat_user_skill (
    id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键',
    user_id BIGINT NOT NULL COMMENT '所属用户 ID',
    skill_name VARCHAR(128) NOT NULL COMMENT '技能名称',
    skill_description VARCHAR(255) NULL COMMENT '技能简介，用于前端下拉框和管理页面展示',
    system_prompt LONGTEXT NOT NULL COMMENT '技能提示词正文，发送消息时会被注入为 system prompt',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
    INDEX idx_chat_user_skill_user_id (user_id),
    CONSTRAINT uk_chat_user_skill_user_name UNIQUE (user_id, skill_name),
    CONSTRAINT fk_chat_user_skill_user FOREIGN KEY (user_id) REFERENCES chat_user(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户技能表';

CREATE TABLE IF NOT EXISTS chat_user_image_history (
    id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键',
    user_id BIGINT NOT NULL COMMENT '所属用户 ID',
    operation_type VARCHAR(32) NOT NULL COMMENT '图片操作类型：generate/edit/compatible',
    model VARCHAR(128) NOT NULL COMMENT '模型名',
    prompt LONGTEXT NOT NULL COMMENT '本次请求提示词',
    image_data_url LONGTEXT NOT NULL COMMENT '结果图片 data URL',
    result_info VARCHAR(512) NULL COMMENT '结果摘要',
    response_json LONGTEXT NULL COMMENT '原始响应 JSON',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    INDEX idx_chat_user_image_history_user_id (user_id),
    CONSTRAINT fk_chat_user_image_history_user FOREIGN KEY (user_id) REFERENCES chat_user(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户图片历史表';

INSERT INTO chat_user_skill (user_id, skill_name, skill_description, system_prompt)
SELECT u.id,
       '张雪峰',
       '张雪峰视角的教育与职业规划顾问，适合分析高考志愿、专业选择、职业路径和阶层流动问题。',
       CONVERT( USING utf8mb4)
FROM chat_user u
WHERE u.account_name = 'admin'
  AND NOT EXISTS (
      SELECT 1
      FROM chat_user_skill s
      WHERE s.user_id = u.id
        AND s.skill_name = '张雪峰'
  );
